Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &CreDtaVct.IsEmpty() print printBlockFilterCreDtaVct EndIf If not &CreDtaVct_To.IsEmpty() &CreDtaVct_To_Description = format('%1 (%2)', "Vcto.", "à") print printBlockFilterCreDtaVct_To EndIf If not &CreRecPag.IsEmpty() &FilterCreRecPagValueDescription = &CreRecPag.EnumerationDescription()
print printBlockFilterCreRecPag EndIf If not &CreSts.IsEmpty() &FilterCreStsValueDescription = &CreSts.EnumerationDescription()
print printBlockFilterCreSts EndIf If not &CreDtaPrt.IsEmpty() print printBlockFilterCreDtaPrt EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CRECLICOD' &CreCliCod1.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod1.IsEmpty() &CreCliCod = &CreCliCod1 print printBlockFilterCreCliCod EndIf Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCliRaz1.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &CreCliRaz = &CreCliRaz1 print printBlockFilterCreCliRaz EndIf Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator1 = 1 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &CreDupNro = &CreDupNro1 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &CreCbrNom = &CreCbrNom1 print printBlockFilterCreCbrNom EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CRECLICOD' &CreCliCod2.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod2.IsEmpty() &CreCliCod = &CreCliCod2 print printBlockFilterCreCliCod EndIf Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCliRaz2.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &CreCliRaz = &CreCliRaz2 print printBlockFilterCreCliRaz EndIf Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator2 = 1 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &CreDupNro = &CreDupNro2 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &CreCbrNom = &CreCbrNom2 print printBlockFilterCreCbrNom EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CRECLICOD' &CreCliCod3.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod3.IsEmpty() &CreCliCod = &CreCliCod3 print printBlockFilterCreCliCod EndIf Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCliRaz3.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &FilterCreCliRazDescription = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &CreCliRaz = &CreCliRaz3 print printBlockFilterCreCliRaz EndIf Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator3 = 1 &FilterCreDupNroDescription = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &CreDupNro = &CreDupNro3 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &FilterCreCbrNomDescription = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &CreCbrNom = &CreCbrNom3 print printBlockFilterCreCbrNom EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreRecPag FilCod CreDtaVct when &OrderedBy = 1 order CreCod when &OrderedBy = 2 AND &OrderedDsc = False order (CreCod) when &OrderedBy = 2 AND &OrderedDsc = True order CreDupNro when &OrderedBy = 3 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 3 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 5 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 5 AND &OrderedDsc = True order CreVlrDup when &OrderedBy = 6 AND &OrderedDsc = False order (CreVlrDup) when &OrderedBy = 6 AND &OrderedDsc = True order CreVlrSdo when &OrderedBy = 7 AND &OrderedDsc = False order (CreVlrSdo) when &OrderedBy = 7 AND &OrderedDsc = True order CreBloNro when &OrderedBy = 8 AND &OrderedDsc = False order (CreBloNro) when &OrderedBy = 8 AND &OrderedDsc = True order CreDtaPrt when &OrderedBy = 9 AND &OrderedDsc = False order (CreDtaPrt) when &OrderedBy = 9 AND &OrderedDsc = True order CreVenCod when &OrderedBy = 10 AND &OrderedDsc = False order (CreVenCod) when &OrderedBy = 10 AND &OrderedDsc = True order CrePedCod when &OrderedBy = 11 AND &OrderedDsc = False order (CrePedCod) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWDuplicataAnuencia(&CreDtaVct, &CreDtaVct_To, &CreRecPag, &CreSts, &CreDtaPrt, &DynamicFiltersSelector1 , &DynamicFiltersOperator1, &CreCliCod1, &CreCliRaz1, &CreDupNro1, &CreCbrNom1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &DynamicFiltersOperator2, &CreCliCod2, &CreCliRaz2, &CreDupNro2, &CreCbrNom2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CreCliCod3, &CreCliRaz3, &CreDupNro3 , &CreCbrNom3) &gridCreCliCodRaz = CreCliCodRaz
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWDuplicataAnuenciaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWDuplicataAnuenciaGridState")) Else &GridState.FromXml(&Session.Get(!"WWDuplicataAnuenciaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAPRT" &CreDtaPrt.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
